// ─────────────────────────────────────────────
// BLOCK RANDOMIZATION + ANONYMOUS ID GENERATION
// ─────────────────────────────────────────────
const staticData = $getWorkflowStaticData('global');

if (!staticData.counts) {
  staticData.counts = { arm1: 0, arm2: 0, arm3: 0, arm4: 0 };
  staticData.totalParticipants = 0;
  staticData.currentBlock = [];
}

// Generate anonymous UUID
const uuid = 'xxxx-xxxx-xxxx'.replace(/x/g, () =>
  Math.floor(Math.random() * 16).toString(16)
);
const participantId = 'P-' + uuid.toUpperCase();

// Block randomization (block size = 4, Fisher-Yates shuffle)
const total = staticData.totalParticipants;
const posInBlock = total % 4;

if (posInBlock === 0) {
  const arms = [1, 2, 3, 4];
  for (let i = arms.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [arms[i], arms[j]] = [arms[j], arms[i]];
  }
  staticData.currentBlock = arms;
}

const assignedArm = staticData.currentBlock[posInBlock];
staticData.counts['arm' + assignedArm]++;
staticData.totalParticipants++;

// ─────────────────────────────────────────────
// FORM URLS — replace with your own JotForm links
// Arm 1: Dependency-associated appearance + Objective pain (fracture)
// Arm 2: Dependency-associated appearance + Subjective pain (renal colic)
// Arm 3: Non-dependency appearance + Objective pain (fracture)
// Arm 4: Non-dependency appearance + Subjective pain (renal colic)
// ─────────────────────────────────────────────
const formUrls = {
  1: 'https://form.jotform.com/ARM_1_FORM_ID',
  2: 'https://form.jotform.com/ARM_2_FORM_ID',
  3: 'https://form.jotform.com/ARM_3_FORM_ID',
  4: 'https://form.jotform.com/ARM_4_FORM_ID'
};

const armLabels = {
  1: 'Dependency appearance + Objective pain',
  2: 'Dependency appearance + Subjective pain',
  3: 'Non-dependency appearance + Objective pain',
  4: 'Non-dependency appearance + Subjective pain'
};

return {
  participantId,
  assignedArm,
  assignedArmLabel: armLabels[assignedArm],
  redirectUrl: formUrls[assignedArm],
  timestamp: new Date().toISOString(),
  currentCounts: { ...staticData.counts },
  totalParticipants: staticData.totalParticipants
};
